var e=`Възпроизвеждане`,t=`Пауза`,n=`Продължителност`,r=`НА ЖИВО`,i=`Заредено`,a=`Прогрес`,o=`Цял екран`,s=`Без звук`,c=`Със звук`,l=`Субтитри`,u=`Аудио надписи`,d=`Глави`,f={Play:e,Pause:t,"Current Time":`Текущо време`,Duration:n,"Remaining Time":`Оставащо време`,"Stream Type":`Тип на потока`,LIVE:r,Loaded:i,Progress:a,Fullscreen:o,"Exit Fullscreen":`Спиране на цял екран`,Mute:s,Unmute:c,"Playback Rate":`Скорост на възпроизвеждане`,Subtitles:l,"subtitles off":`Спряни субтитри`,Captions:u,"captions off":`Спряни аудио надписи`,Chapters:d,"You aborted the media playback":`Спряхте възпроизвеждането на видеото`,"A network error caused the media download to fail part-way.":`Грешка в мрежата провали изтеглянето на видеото.`,"The media could not be loaded, either because the server or network failed or because the format is not supported.":`Видеото не може да бъде заредено заради проблем със сървъра или мрежата или защото този формат не е поддържан.`,"The media playback was aborted due to a corruption problem or because the media used features your browser did not support.":`Възпроизвеждането на видеото беше прекъснато заради проблем с файла или защото видеото използва опции които браузърът Ви не поддържа.`,"No compatible source was found for this media.":`Не беше намерен съвместим източник за това видео.`};export{u as Captions,d as Chapters,n as Duration,o as Fullscreen,r as LIVE,i as Loaded,s as Mute,t as Pause,e as Play,a as Progress,l as Subtitles,c as Unmute,f as default};